/**
 * Tests for server.js (HTTP Server, Socket.IO & Database Initialisation)
 * Uses syntax + structure validation — the file has 37+ deps
 * making full mock-based loading impractical.
 * @generated by P#105
 */
'use strict';

const fs = require('fs');
const path = require('path');
const vm = require('vm');

const SRC = path.resolve(__dirname, '../../server.js');

describe('server.js', () => {
  let source;
  beforeAll(() => {
    source = fs.readFileSync(SRC, 'utf8');
  });

  test('file exists', () => {
    expect(fs.existsSync(SRC)).toBe(true);
  });

  test('is syntactically valid JavaScript', () => {
    expect(() => new vm.Script(source, { filename: 'server.js' })).not.toThrow();
  });

  test('requires http module', () => {
    expect(source).toMatch(/require\s*\(\s*['"]http['"]\s*\)/);
  });

  test('requires socket.io', () => {
    expect(source).toMatch(/require\s*\(\s*['"]socket\.io['"]\s*\)/);
  });

  test('requires ./app', () => {
    expect(source).toMatch(/require\s*\(\s*['"]\.\/app['"]\s*\)/);
  });

  test('creates HTTP server via http.createServer', () => {
    expect(source).toMatch(/http\.createServer\s*\(/);
  });

  test('connects to database', () => {
    expect(source).toMatch(/connectDB\s*\(/);
  });

  test('seeds database', () => {
    expect(source).toMatch(/seedDatabase/);
  });

  test('registers Mongoose global plugins', () => {
    expect(source).toMatch(/registerGlobalPlugins\s*\(/);
  });

  test('handles OpenTelemetry conditionally', () => {
    expect(source).toMatch(/OTEL_ENABLED/);
  });

  test('sets server timeouts', () => {
    expect(source).toMatch(/server\.timeout/);
    expect(source).toMatch(/server\.keepAliveTimeout/);
  });

  test('supports graceful shutdown', () => {
    expect(source).toMatch(/setupGracefulShutdown/);
  });

  test('exports app', () => {
    expect(source).toMatch(/module\.exports\.app/);
  });

  test('exports io', () => {
    expect(source).toMatch(/module\.exports\.io/);
  });

  test('exports server', () => {
    expect(source).toMatch(/module\.exports\.server/);
  });

  test('starts server when run directly', () => {
    expect(source).toMatch(/require\.main\s*===\s*module/);
    expect(source).toMatch(/server\.listen/);
  });
});
